import{_ as i,o,c as d,ai as a}from"./chunks/framework.CsYGeNYI.js";const m=JSON.parse('{"title":"菜单栏","description":"","frontmatter":{"read_when":["调整 Mac 菜单 UI 或状态逻辑"],"summary":"菜单栏状态逻辑及向用户展示的内容","title":"菜单栏","x-i18n":{"generated_at":"2026-02-01T21:33:00Z","model":"claude-opus-4-5","provider":"pi","source_hash":"8eb73c0e671a76aae4ebb653c65147610bf3e6d3c9c0943d150e292e7761d16d","source_path":"platforms/mac/menu-bar.md","workflow":15}},"headers":[],"relativePath":"zh-CN/platforms/mac/menu-bar.md","filePath":"zh-CN/platforms/mac/menu-bar.md","lastUpdated":1771906665000}'),l={name:"zh-CN/platforms/mac/menu-bar.md"};function c(t,e,r,n,s,h){return o(),d("div",null,[...e[0]||(e[0]=[a('<h1 id="菜单栏状态逻辑" tabindex="-1"><a class="header-anchor" href="#菜单栏状态逻辑">#</a> 菜单栏状态逻辑</h1><h2 id="显示内容" tabindex="-1"><a class="header-anchor" href="#显示内容">#</a> 显示内容</h2><ul><li>我们在菜单栏图标和菜单的第一行状态行中展示当前智能体的工作状态。</li><li>工作活跃时隐藏健康状态；当所有会话空闲时恢复显示。</li><li>菜单中的&quot;节点&quot;区块仅列出<strong>设备</strong>（通过 <code>node.list</code> 配对的节点），不包括客户端/在线状态条目。</li><li>当提供商用量快照可用时，&quot;用量&quot;部分会显示在上下文下方。</li></ul><h2 id="状态模型" tabindex="-1"><a class="header-anchor" href="#状态模型">#</a> 状态模型</h2><ul><li>会话：事件携带 <code>runId</code>（每次运行）以及载荷中的 <code>sessionKey</code>。&quot;main&quot; 会话的键为 <code>main</code>；如果不存在，则回退到最近更新的会话。</li><li>优先级：main 始终优先。如果 main 处于活跃状态，立即显示其状态。如果 main 空闲，则显示最近活跃的非 main 会话。活动进行中不会来回切换；仅在当前会话进入空闲或 main 变为活跃时才切换。</li><li>活动类型： <ul><li><code>job</code>：高层命令执行（<code>state: started|streaming|done|error</code>）。</li><li><code>tool</code>：<code>phase: start|result</code>，包含 <code>toolName</code> 和 <code>meta/args</code>。</li></ul></li></ul><h2 id="iconstate-枚举-swift" tabindex="-1"><a class="header-anchor" href="#iconstate-枚举-swift">#</a> IconState 枚举（Swift）</h2><ul><li><code>idle</code></li><li><code>workingMain(ActivityKind)</code></li><li><code>workingOther(ActivityKind)</code></li><li><code>overridden(ActivityKind)</code>（调试覆盖）</li></ul><h3 id="activitykind-→-图标符号" tabindex="-1"><a class="header-anchor" href="#activitykind-→-图标符号">#</a> ActivityKind → 图标符号</h3><ul><li><code>exec</code> → 💻</li><li><code>read</code> → 📄</li><li><code>write</code> → ✍️</li><li><code>edit</code> → 📝</li><li><code>attach</code> → 📎</li><li>默认 → 🛠️</li></ul><h3 id="视觉映射" tabindex="-1"><a class="header-anchor" href="#视觉映射">#</a> 视觉映射</h3><ul><li><code>idle</code>：正常小动物图标。</li><li><code>workingMain</code>：带图标符号的徽章，完整色调，腿部&quot;工作&quot;动画。</li><li><code>workingOther</code>：带图标符号的徽章，柔和色调，无快跑动画。</li><li><code>overridden</code>：无论活动状态如何，使用所选的图标符号/色调。</li></ul><h2 id="状态行文本-菜单" tabindex="-1"><a class="header-anchor" href="#状态行文本-菜单">#</a> 状态行文本（菜单）</h2><ul><li>工作活跃时：<code>&lt;会话角色&gt; · &lt;活动标签&gt;</code><ul><li>示例：<code>Main · exec: pnpm test</code>、<code>Other · read: apps/macos/Sources/OpenSoul/AppState.swift</code>。</li></ul></li><li>空闲时：回退显示健康摘要。</li></ul><h2 id="事件接收" tabindex="-1"><a class="header-anchor" href="#事件接收">#</a> 事件接收</h2><ul><li>来源：控制渠道 <code>agent</code> 事件（<code>ControlChannel.handleAgentEvent</code>）。</li><li>解析字段： <ul><li><code>stream: &quot;job&quot;</code>，包含 <code>data.state</code> 用于启动/停止。</li><li><code>stream: &quot;tool&quot;</code>，包含 <code>data.phase</code>、<code>name</code>，可选 <code>meta</code>/<code>args</code>。</li></ul></li><li>标签： <ul><li><code>exec</code>：<code>args.command</code> 的第一行。</li><li><code>read</code>/<code>write</code>：缩短的路径。</li><li><code>edit</code>：路径加上从 <code>meta</code>/diff 计数推断的变更类型。</li><li>回退：工具名称。</li></ul></li></ul><h2 id="调试覆盖" tabindex="-1"><a class="header-anchor" href="#调试覆盖">#</a> 调试覆盖</h2><ul><li>设置 ▸ 调试 ▸ &quot;图标覆盖&quot; 选择器： <ul><li><code>系统（自动）</code>（默认）</li><li><code>工作中：main</code>（按工具类型）</li><li><code>工作中：other</code>（按工具类型）</li><li><code>空闲</code></li></ul></li><li>通过 <code>@AppStorage(&quot;iconOverride&quot;)</code> 存储；映射到 <code>IconState.overridden</code>。</li></ul><h2 id="测试清单" tabindex="-1"><a class="header-anchor" href="#测试清单">#</a> 测试清单</h2><ul><li>触发 main 会话任务：验证图标立即切换且状态行显示 main 标签。</li><li>main 空闲时触发非 main 会话任务：图标/状态显示非 main；保持稳定直到完成。</li><li>在 other 活跃时启动 main：图标立即切换到 main。</li><li>快速连续工具调用：确保徽章不会闪烁（工具结果的 TTL 宽限期）。</li><li>所有会话空闲后健康行重新出现。</li></ul>',19)])])}const p=i(l,[["render",c]]);export{m as __pageData,p as default};
